  if (/SET-|settings/i.test(block)) {
    const lines=block.trim().split(/\r?\n/);
    if (!lines[0]) continue;
    console.log('### '+lines[0]);
    for (const line of lines.slice(1,8)) if (line.trim()) console.log(line);
    console.log('---');
